import{_ as a}from"./chunks/文件受限图.DsG20F9s.js";import{_ as l,o as t,c as d,a2 as i}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"مراجعة الصور ووضع الوصول","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/Safety/image-moderation-and-access-mode.md","filePath":"ar-SA/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),o={name:"ar-SA/Safety/image-moderation-and-access-mode.md"};function r(n,e,s,c,p,h){return t(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="مراجعة-الصور-ووضع-الوصول" tabindex="-1">مراجعة الصور ووضع الوصول <a class="header-anchor" href="#مراجعة-الصور-ووضع-الوصول" aria-label="Permalink to &quot;مراجعة الصور ووضع الوصول&quot;">​</a></h1><p>تمنح مراجعة الصور تقييمات عمرية للصور المرفوعة. يحدد وضع الوصول أي التقييمات تظهر عبر الوصول العام.</p><p>يؤثر ذلك على public gallery وروابط الملفات العامة و random image API. لا يقيّد لوحة الإدارة، فالمسؤولون يستطيعون عرض كل الملفات وإدارتها.</p><h2 id="أين-تضبطه؟" tabindex="-1">أين تضبطه؟ <a class="header-anchor" href="#أين-تضبطه؟" aria-label="Permalink to &quot;أين تضبطه؟&quot;">​</a></h2><p>افتح لوحة الإدارة، ثم انتقل إلى:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>الإعدادات الرئيسية:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="ماذا-يفعل-access-mode؟" tabindex="-1">ماذا يفعل Access Mode؟ <a class="header-anchor" href="#ماذا-يفعل-access-mode؟" aria-label="Permalink to &quot;ماذا يفعل Access Mode؟&quot;">​</a></h2><p>يحدد Access mode التقييمات العمرية المسموح بعرضها للعامة.</p><p>الأوضاع الحالية:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>التقييمات الظاهرة للعامة</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>General فقط</td></tr></tbody></table><p>الوضع الافتراضي هو Adult mode.</p><p>للمواقع الخاصة أو التي تحتوي محتوى مخصصًا للبالغين قد يكون Adult mode مناسبًا. أما للمعارض العامة المحافظة فاختر Youth أو Teen أو Child mode.</p><h2 id="ماذا-يفعل-تفعيل-المراجعة؟" tabindex="-1">ماذا يفعل تفعيل المراجعة؟ <a class="header-anchor" href="#ماذا-يفعل-تفعيل-المراجعة؟" aria-label="Permalink to &quot;ماذا يفعل تفعيل المراجعة؟&quot;">​</a></h2><p>عند تفعيل المراجعة، يستدعي ImgBed مزود المراجعة المختار أثناء الرفع ويحفظ التقييم العمري المكتشف.</p><p>التقييمات الرئيسية:</p><table tabindex="0"><thead><tr><th>التقييم</th><th>المعنى</th></tr></thead><tbody><tr><td>General</td><td>محتوى عام آمن</td></tr><tr><td>R12</td><td>محتوى حساس بدرجة خفيفة</td></tr><tr><td>R16</td><td>محتوى حساس بدرجة متوسطة</td></tr><tr><td>R18</td><td>محتوى للبالغين</td></tr></tbody></table><p>تُستخدم نتيجة المراجعة عند تحديد الوصول العام.</p><p>إذا لم تكن المراجعة مفعلة، أو كانت الملفات القديمة بلا تقييم، تُعامل تلك الملفات كملفات unrated. عدم وجود تقييم لا يخفيها تلقائيًا من public gallery أو random image API.</p><h2 id="اختيار-moderation-provider" tabindex="-1">اختيار Moderation Provider <a class="header-anchor" href="#اختيار-moderation-provider" aria-label="Permalink to &quot;اختيار Moderation Provider&quot;">​</a></h2><p>المزودون المتاحون:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>لكل مزود متطلبات مختلفة:</p><ul><li>moderatecontent.com يتطلب غالبًا API Key.</li><li>nsfwjs يتطلب غالبًا API endpoint URL.</li><li>Sightengine يتطلب API user و API secret.</li></ul><p>اختر حسب حسابك، والتوفر، وجودة الكشف. ما دام التفعيل والإعداد صحيحين، يحاول ImgBed كتابة تقييم الصورة أثناء الرفع.</p><h2 id="التأثير-على-public-gallery" tabindex="-1">التأثير على Public Gallery <a class="header-anchor" href="#التأثير-على-public-gallery" aria-label="Permalink to &quot;التأثير على Public Gallery&quot;">​</a></h2><p>تفلتر public gallery الملفات حسب access mode.</p><p>أمثلة:</p><ul><li>Adult mode: يمكن أن تظهر صور R18.</li><li>Youth mode: تُخفى صور R18.</li><li>Teen mode: تُخفى صور R16 و R18.</li><li>Child mode: تظهر صور General فقط.</li></ul><p>هذا يؤثر على الوصول العام العادي فقط. لوحة الإدارة تعرض كل الملفات.</p><h2 id="التأثير-على-روابط-الملفات-العامة" tabindex="-1">التأثير على روابط الملفات العامة <a class="header-anchor" href="#التأثير-على-روابط-الملفات-العامة" aria-label="Permalink to &quot;التأثير على روابط الملفات العامة&quot;">​</a></h2><p>روابط الملفات العامة هي روابط الصور المباشرة التي يفتحها الزوار.</p><p>إذا كان تقييم الملف مسموحًا في access mode الحالي، يعيد ImgBed الصورة الأصلية.</p><p>إذا كان التقييم أعلى من المستوى المسموح، لا يعيد الوصول العام العادي الصورة الأصلية. بدلًا من ذلك يعيد ImgBed نتيجة الحجب المضبوطة أو صورة بديلة.</p><p>مثال:</p><ul><li>الوضع الحالي Child mode.</li><li>الصورة مصنفة R18.</li><li>زائر يفتح الرابط العام مباشرة.</li><li>لا يعيد ImgBed الصورة الأصلية R18 لذلك الزائر.</li></ul><p><img src="'+a+'" alt="صورة ملف مقيّدة" loading="lazy"></p><p>المسؤولون الذين يعرضون الملفات من لوحة الإدارة لا يتأثرون بهذا القيد.</p><h2 id="التأثير-على-random-image-api" tabindex="-1">التأثير على Random Image API <a class="header-anchor" href="#التأثير-على-random-image-api" aria-label="Permalink to &quot;التأثير على Random Image API&quot;">​</a></h2><p>يفلتر random image API أيضًا مجموعة المرشحين حسب access mode.</p><p>في Child mode تُختار الصور العشوائية فقط من ملفات General.</p><p>في Youth mode قد تأتي الصور من General و R12 و R16، وليس من R18.</p><p>هذا يمنع random image API من تجاوز قيود public gallery.</p><h2 id="العلاقة-مع-قواعد-القوائم" tabindex="-1">العلاقة مع قواعد القوائم <a class="header-anchor" href="#العلاقة-مع-قواعد-القوائم" aria-label="Permalink to &quot;العلاقة مع قواعد القوائم&quot;">​</a></h2><p>Access mode ليس قاعدة الوصول العام الوحيدة. يعمل مع قواعد allow/block list.</p><p>ببساطة:</p><ul><li>محتوى allowlist يُعامل أولًا كمحتوى عام.</li><li>محتوى blocklist لا يمكن عرضه مباشرة للزوار العاديين.</li><li>المحتوى غير الموجود في أي قائمة يُفحص بعد ذلك حسب access mode.</li></ul><p>إذا كانت الصورة مقيّدة بالتقييم العمري وقواعد القوائم معًا، فلن يستطيع الزوار العاديون عرض الملف الأصلي مباشرة.</p><h2 id="الإعدادات-الموصى-بها" tabindex="-1">الإعدادات الموصى بها <a class="header-anchor" href="#الإعدادات-الموصى-بها" aria-label="Permalink to &quot;الإعدادات الموصى بها&quot;">​</a></h2><p>للمواقع العامة:</p><ul><li>فعّل المراجعة.</li><li>اختر access mode يناسب جمهور الموقع.</li><li>استخدم Child mode أو Teen mode للزوار من كل الأعمار.</li><li>تجنب Adult mode إذا لم ترغب في عرض محتوى للبالغين للعامة.</li><li>راجع تقييمات الملفات في لوحة الإدارة وعدّلها يدويًا عند الحاجة.</li></ul><p>للمواقع الخاصة أو الشخصية:</p><ul><li>Adult mode مناسب غالبًا.</li><li>فعّل المراجعة إذا كانت مفيدة.</li><li>راجع وعدّل التقييمات من لوحة الإدارة عند الحاجة.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="هل-تختفي-الملفات-من-لوحة-الإدارة-بعد-تغيير-access-mode؟" tabindex="-1">هل تختفي الملفات من لوحة الإدارة بعد تغيير Access Mode؟ <a class="header-anchor" href="#هل-تختفي-الملفات-من-لوحة-الإدارة-بعد-تغيير-access-mode؟" aria-label="Permalink to &quot;هل تختفي الملفات من لوحة الإدارة بعد تغيير Access Mode؟&quot;">​</a></h3><p>لا.</p><p>Access mode يؤثر على الوصول العام العادي فقط ولا يؤثر على لوحة الإدارة.</p><h3 id="لماذا-عرضت-public-gallery-صورًا-أقل-بعد-التحويل-إلى-child-mode؟" tabindex="-1">لماذا عرضت Public Gallery صورًا أقل بعد التحويل إلى Child Mode؟ <a class="header-anchor" href="#لماذا-عرضت-public-gallery-صورًا-أقل-بعد-التحويل-إلى-child-mode؟" aria-label="Permalink to &quot;لماذا عرضت Public Gallery صورًا أقل بعد التحويل إلى Child Mode؟&quot;">​</a></h3><p>Child mode يسمح فقط بعرض ملفات General للعامة. تُفلتر ملفات R12 و R16 و R18.</p><h3 id="هل-يمكن-للروابط-العامة-فتح-صور-للبالغين؟" tabindex="-1">هل يمكن للروابط العامة فتح صور للبالغين؟ <a class="header-anchor" href="#هل-يمكن-للروابط-العامة-فتح-صور-للبالغين؟" aria-label="Permalink to &quot;هل يمكن للروابط العامة فتح صور للبالغين؟&quot;">​</a></h3><p>إذا كان access mode الحالي لا يسمح بذلك التقييم، فلن تعيد الروابط العامة العادية الصورة الأصلية.</p><h3 id="هل-يمكن-لـ-random-image-api-إعادة-صور-مقيّدة؟" tabindex="-1">هل يمكن لـ Random Image API إعادة صور مقيّدة؟ <a class="header-anchor" href="#هل-يمكن-لـ-random-image-api-إعادة-صور-مقيّدة؟" aria-label="Permalink to &quot;هل يمكن لـ Random Image API إعادة صور مقيّدة؟&quot;">​</a></h3><p>لا.</p><p>يفلتر random image API المرشحين حسب access mode الحالي.</p><h3 id="ماذا-يحدث-للصور-القديمة-غير-المصنفة؟" tabindex="-1">ماذا يحدث للصور القديمة غير المصنفة؟ <a class="header-anchor" href="#ماذا-يحدث-للصور-القديمة-غير-المصنفة؟" aria-label="Permalink to &quot;ماذا يحدث للصور القديمة غير المصنفة؟&quot;">​</a></h3><p>لا تُخفى الصور غير المصنفة تلقائيًا لمجرد عدم وجود نتيجة مراجعة. يمكنك تعديل تقييمها لاحقًا من لوحة الإدارة.</p>',67)])])}const g=l(o,[["render",r]]);export{b as __pageData,g as default};
